  { ar:{label:'دعاء الوحدة',text:'اللَّهُمَّ أَلِّفْ بَيْنَ قُلُوبِنَا وَأَصْلِحْ ذَاتَ بَيْنِنَا وَاهْدِنَا سُبُلَ السَّلَامِ',tr:'من دعاء النبي ﷺ'}, en:{label:'Dua for Unity',text:'Allahumma allif bayna quloobina wa aslih dhata baynina wahdina subul as-salam',tr:'O God, bring our hearts together, reconcile between us, and guide us to paths of peace'}, fr:{label:'Dua pour l\'Unité',text:'Allahumma allif bayna quloobina wa aslih dhata baynina wahdina subul as-salam',tr:'Ô Dieu, rassemble nos cœurs, réconcilie entre nous et guide-nous vers les voies de la paix'} },
  { ar:{label:'دعاء العلم',text:'اللَّهُمَّ انْفَعْنِي بِمَا عَلَّمْتَنِي وَعَلِّمْنِي مَا يَنْفَعُنِي وَزِدْنِي عِلْمًا',tr:'حديث شريف'}, en:{label:'Dua for Knowledge',text:'Allahumma infa\'ni bima allamtani wa allimni ma yanfa\'uni wa zidni ilma',tr:'O God, benefit me by what You have taught me, teach me what will benefit me, and increase me in knowledge'}, fr:{label:'Dua pour le Savoir',text:'Allahumma infa\'ni bima allamtani wa allimni ma yanfa\'uni wa zidni ilma',tr:'Ô Dieu, fais-moi profiter de ce que Tu m\'as enseigné, enseigne-moi ce qui me sera utile et augmente-moi en savoir'} },
  { ar:{label:'دعاء حسن الخاتمة',text:'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ',tr:'البقرة ٢: ٢٠١'}, en:{label:'Dua for Good End',text:'Rabbana atina fid-dunya hasanatan wa fil akhirati hasanatan wa qina adhab an-nar',tr:'Our Lord, give us good in this world and in the Hereafter and protect us from the Fire (2:201)'}, fr:{label:'Dua pour une Bonne Fin',text:'Rabbana atina fid-dunya hasanatan wa fil akhirati hasanatan wa qina adhab an-nar',tr:'Notre Seigneur, donne-nous le bien ici-bas et dans l\'au-delà et protège-nous du Feu (2:201)'} }
