document.addEventListener('DOMContentLoaded', () => {
  setTheme(theme); setLang(lang); initTabs(); initSplash(); initScrollTop(); initSwipeGestures(); initParticles();
  renderHome(); renderCards(); renderResistance(); renderHabits(); renderQuiz(); renderAbout(); renderHelp(); renderDuas(); initScrollReveal(); initKeyboardNav();
});

function initSplash() {
  let count = 5; const el = document.getElementById('splashCount');
  const featuresEl = document.getElementById('splashFeatures');
  if (featuresEl) featuresEl.innerHTML = T[lang].splashFeatures.map((f, i) => `<div class="splash-feature" style="animation-delay:${0.3 + i * 0.3}s">${f}</div>`).join('');
  const interval = setInterval(() => { count--; if (el) el.textContent = count; if (count <= 0) { dismissSplash(); clearInterval(interval); } }, 1000);
}
function dismissSplash() { const s = document.getElementById('splash'); if (s) { s.classList.add('hidden'); setTimeout(() => s.style.display = 'none', 500); } playSound('click'); }

function setLang(l) {
  lang = l; localStorage.setItem('istimar-lang', l);
  const isRTL = l === 'ar'; document.documentElement.lang = l; document.documentElement.dir = isRTL ? 'rtl' : 'ltr'; document.body.dir = isRTL ? 'rtl' : 'ltr';
  document.querySelectorAll('.lang-opt').forEach(b => b.classList.toggle('active', b.dataset.lang === l));
  const t = T[l]; const set = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
  set('appTitle', t.appTitle); set('splashSub', t.splashSub); set('splashHint', t.splashHint);
  set('tabHome', t.tabHome); set('tabCards', t.tabCards); set('tabResistance', t.tabResistance);
  set('tabHabits', t.tabHabits); set('tabQuiz', t.tabQuiz); set('tabAbout', t.tabAbout);
  set('cardsTitle', t.cardsTitle); set('cardsDesc', t.cardsDesc);
  set('resistanceTitle', t.resistanceTitle); set('resistanceDesc', t.resistanceDesc);
  set('habitsTitle', t.habitsTitle); set('habitsDesc', t.habitsDesc);
  set('quizTitle', t.quizTitle); set('quizDesc', t.quizDesc);
  set('helpTitle', t.helpTitle); set('duaPanelTitle', t.duaPanelTitle); set('habitsReset', t.resetBtn);
  renderHome(); renderCards(); renderResistance(); renderHabits(); renderQuiz(); renderAbout(); renderHelp(); renderDuas();
  const featuresEl = document.getElementById('splashFeatures');
  if (featuresEl) featuresEl.innerHTML = T[l].splashFeatures.map((f, i) => `<div class="splash-feature" style="animation-delay:${0.3 + i * 0.3}s">${f}</div>`).join('');
}

function setTheme(t) { theme = t; document.documentElement.dataset.theme = t; localStorage.setItem('istimar-theme', t); const idx = themes.indexOf(t); const el = document.getElementById('themeIcon'); if (el) el.textContent = themeIcons[idx]; }
function cycleTheme() { const idx = (themes.indexOf(theme) + 1) % themes.length; setTheme(themes[idx]); showToast(themeNames[themes[idx]]); playSound('theme'); }

function initTabs() { document.querySelectorAll('.tab').forEach(tab => { tab.addEventListener('click', () => { document.querySelectorAll('.tab').forEach(t => t.classList.remove('active')); document.querySelectorAll('.panel').forEach(p => p.classList.remove('active')); tab.classList.add('active'); const panel = document.getElementById('panel-' + tab.dataset.tab); if (panel) panel.classList.add('active'); window.scrollTo({top:0, behavior:'smooth'}); playSound('click'); }); }); }

function renderHome() {
  const t = T[lang]; const dayIdx = new Date().getDate() % CARDS.length; const c = CARDS[dayIdx]; const cd = c[lang];
  document.getElementById('dailyCard').innerHTML = `<div class="daily-label">${t.dailyLabel}</div><div class="daily-title">${cd.title}</div><div class="daily-body">${cd.desc}</div><div class="daily-action" onclick="document.querySelector('[data-tab=cards]').click()">${t.tabCards} &#8594;</div>`;
  const sections = [{icon:'🏴',tab:'cards',title:t.tabCards,desc:lang==='ar'?'٢٠ بطاقة':lang==='fr'?'20 cartes':'20 cards'},{icon:'🛡️',tab:'resistance',title:t.tabResistance,desc:lang==='ar'?'طريق المقاومة':lang==='fr'?'Chemin de résistance':'Path of resistance'},{icon:'📋',tab:'habits',title:t.tabHabits,desc:lang==='ar'?'تتبع يومي':lang==='fr'?'Suivi quotidien':'Daily tracking'},{icon:'🤔',tab:'quiz',title:t.tabQuiz,desc:lang==='ar'?'اختبر وعيك':lang==='fr'?'Testez-vous':'Test yourself'},{icon:'📖',tab:'about',title:t.tabAbout,desc:lang==='ar'?'عن الكتاب':lang==='fr'?'Le livre':'The book'}];
  document.getElementById('homeGrid').innerHTML = sections.map(s => `<div class="home-card" onclick="document.querySelector('[data-tab=${s.tab}]').click()"><span class="hc-icon">${s.icon}</span><div class="hc-title">${s.title}</div><div class="hc-desc">${s.desc}</div></div>`).join('');
}

function renderCards() {
  const t = T[lang];
  const searchBar = `<div class="search-bar"><input type="text" id="cardsSearch" class="search-input" placeholder="${t.searchPlaceholder}" oninput="filterCards(this.value)"><span class="search-icon">🔍</span></div>`;
  const cards = CARDS.map((c, i) => { const d = c[lang]; return `<div class="principle-card scroll-reveal" id="card-${c.id}" data-search="${d.title.toLowerCase()}"><div class="principle-head" onclick="toggleCard('card-${c.id}')"><span class="principle-num">${c.id}</span><span class="principle-emoji">${c.emoji}</span><span class="principle-title">${d.title}</span><span class="principle-chev">&#9660;</span></div><div class="principle-body"><div class="principle-inner"><p class="principle-desc">${d.desc}</p><div class="verse-box"><div class="verse-arabic">${d.quran}</div><div class="verse-ref">${d.quranRef}</div></div><div class="action-box"><span class="action-icon">💡</span><span>${d.lesson}</span></div><button class="share-btn" onclick="event.stopPropagation();shareCard(${i})"><span class="share-icon">&#128279;</span> ${t.share}</button></div></div></div>`; }).join('');
  document.getElementById('cardsContainer').innerHTML = searchBar + cards;
}
function filterCards(query) { const q = query.toLowerCase().trim(); document.querySelectorAll('.principle-card').forEach(card => { const searchText = card.dataset.search || ''; const title = card.querySelector('.principle-title'); const titleText = title ? title.textContent.toLowerCase() : ''; card.style.display = (!q || searchText.includes(q) || titleText.includes(q)) ? '' : 'none'; }); }
async function shareCard(idx) { const c = CARDS[idx]; const d = c[lang]; const text = `${c.emoji} ${d.title}\n\n${d.desc}\n\n${d.quran}\n💡 ${d.lesson}\n\n— الاستعمار أحقاد وأطماع`; if (navigator.share) { try { await navigator.share({ title: d.title, text }); } catch(e) {} } else { try { await navigator.clipboard.writeText(text); showToast(lang === 'ar' ? 'تم النسخ!' : lang === 'fr' ? 'Copié !' : 'Copied!'); } catch(e) { showToast('Could not copy'); } } }

function renderResistance() {
  const t = T[lang];
  document.getElementById('resistanceContainer').innerHTML = RESISTANCE_DATA.map(r => { const d = r[lang]; return `<div class="anxiety-card scroll-reveal"><div class="anxiety-header"><span class="anxiety-emoji">${r.emoji}</span><span class="anxiety-title">${d.title}</span></div><div class="anxiety-problem"><span class="anxiety-label">${lang==='ar'?'😰 المشكلة':lang==='fr'?'😰 Le Problème':'😰 The Problem'}</span>${d.problem}</div><div class="anxiety-solution"><span class="anxiety-label">${lang==='ar'?'🛡️ الحل':lang==='fr'?'🛡️ La Solution':'🛡️ The Solution'}</span>${d.solution}</div><div class="verse-box"><div class="verse-arabic">${d.verse}</div><div class="verse-ref">${d.verseRef}</div></div></div>`; }).join('');
}

function renderHabits() {
  const today = new Date().toDateString(); let habitsState = JSON.parse(localStorage.getItem('istimar-habits') || '{}');
  if (habitsState.date !== today) { updateStreak(habitsState); habitsState = { date: today, done: [] }; localStorage.setItem('istimar-habits', JSON.stringify(habitsState)); }
  const streak = getStreak(); const streakHTML = streak > 0 ? `<div class="streak-badge">🔥 ${streak} ${T[lang].streakMsg}</div>` : '';
  document.getElementById('habitsContainer').innerHTML = HABITS.map((h, i) => { const d = h[lang]; const isDone = habitsState.done.includes(i); return `<div class="habit-item ${isDone ? 'done' : ''}" onclick="toggleHabit(${i})"><span class="habit-check">${isDone ? '&#10003;' : ''}</span><span class="habit-emoji">${h.emoji}</span><div><div class="habit-label">${d.label}</div><div class="habit-source">${d.source}</div></div></div>`; }).join('');
  const streakEl = document.getElementById('streakBadge'); if (streakEl) streakEl.innerHTML = streakHTML; updateHabitsProgress(habitsState);
}
function toggleHabit(i) { const today = new Date().toDateString(); let hs = JSON.parse(localStorage.getItem('istimar-habits') || '{}'); if (hs.date !== today) hs = { date: today, done: [] }; const idx = hs.done.indexOf(i); if (idx > -1) hs.done.splice(idx, 1); else hs.done.push(i); localStorage.setItem('istimar-habits', JSON.stringify(hs)); renderHabits(); playSound(idx > -1 ? 'click' : 'success'); if (hs.done.length === HABITS.length) { launchConfetti(); showToast(T[lang].allDone); } }
function resetHabits() { localStorage.setItem('istimar-habits', JSON.stringify({ date: new Date().toDateString(), done: [] })); renderHabits(); showToast(lang === 'ar' ? 'تم إعادة التعيين' : lang === 'fr' ? 'Réinitialisé' : 'Reset'); }
function updateHabitsProgress(hs) { const done = hs.done.length, total = HABITS.length, pct = total > 0 ? (done / total * 100) : 0; const fill = document.getElementById('habitsFill'); const txt = document.getElementById('habitsText'); if (fill) fill.style.width = pct + '%'; if (txt) txt.textContent = `${done}/${total}`; }
function updateStreak(prevState) { let streakData = JSON.parse(localStorage.getItem('istimar-streak') || '{"count":0,"lastDate":""}'); if (prevState && prevState.done && prevState.done.length === HABITS.length && prevState.date) { const yesterday = new Date(); yesterday.setDate(yesterday.getDate() - 1); if (prevState.date === yesterday.toDateString()) streakData.count++; else if (prevState.date !== new Date().toDateString()) streakData.count = prevState.done.length === HABITS.length ? 1 : 0; streakData.lastDate = prevState.date; } else if (prevState && prevState.date) { streakData.count = 0; streakData.lastDate = prevState.date; } localStorage.setItem('istimar-streak', JSON.stringify(streakData)); }
function getStreak() { return JSON.parse(localStorage.getItem('istimar-streak') || '{"count":0}').count; }

function launchConfetti() { const canvas = document.getElementById('confettiCanvas'); if (!canvas) return; canvas.style.display = 'block'; const ctx = canvas.getContext('2d'); canvas.width = window.innerWidth; canvas.height = window.innerHeight; const particles = []; const colors = ['#3E2723','#5D4037','#795548','#8D6E63','#A1887F','#BCAAA4','#4E342E']; for (let i = 0; i < 120; i++) particles.push({ x:Math.random()*canvas.width, y:Math.random()*canvas.height-canvas.height, w:Math.random()*10+5, h:Math.random()*6+3, color:colors[Math.floor(Math.random()*colors.length)], vx:(Math.random()-0.5)*4, vy:Math.random()*3+2, rot:Math.random()*360, rotSpeed:(Math.random()-0.5)*10 }); let frame = 0; function draw() { ctx.clearRect(0, 0, canvas.width, canvas.height); particles.forEach(p => { p.x += p.vx; p.y += p.vy; p.rot += p.rotSpeed; ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rot * Math.PI / 180); ctx.fillStyle = p.color; ctx.fillRect(-p.w/2, -p.h/2, p.w, p.h); ctx.restore(); }); frame++; if (frame < 120) requestAnimationFrame(draw); else { ctx.clearRect(0, 0, canvas.width, canvas.height); canvas.style.display = 'none'; } } draw(); }

function renderQuiz() {
  const t = T[lang];
  document.getElementById('quizContainer').innerHTML = QUIZ.map((q, i) => `<div class="quiz-question scroll-reveal" id="quiz-q-${i}"><div class="quiz-q-text">${i+1}. ${q[lang]}</div><div class="quiz-options"><button class="quiz-opt" onclick="selectQuizOpt(${i},2)">${t.yes}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},1)">${t.sometimes}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},0)">${t.no}</button></div></div>`).join('') + `<button class="quiz-submit" onclick="submitQuiz()">${t.submitQuiz}</button>`;
  document.getElementById('quizResult').classList.add('hidden'); window._quizAnswers = {};
}
function selectQuizOpt(qi, val) { window._quizAnswers[qi] = val; document.querySelectorAll(`#quiz-q-${qi} .quiz-opt`).forEach((o, oi) => o.classList.toggle('selected', [2,1,0][oi] === val)); playSound('click'); }
function submitQuiz() {
  const answers = window._quizAnswers || {}; if (Object.keys(answers).length < QUIZ.length) { showToast(lang === 'ar' ? 'أجب على جميع الأسئلة' : lang === 'fr' ? 'Répondez à toutes les questions' : 'Answer all questions'); return; }
  const invertedQs = [1, 3]; let score = 0; Object.entries(answers).forEach(([qi, v]) => { score += invertedQs.includes(parseInt(qi)) ? (2 - v) : v; });
  const max = QUIZ.length * 2, pct = Math.round(score / max * 100); let emoji, title, desc;
  if (pct >= 75) { emoji = '🌟'; title = lang==='ar'?'ممتاز!':lang==='fr'?'Excellent !':'Excellent!'; desc = lang==='ar'?'وعيك بقضايا الاستعمار عالٍ. استمر!':lang==='fr'?'Votre conscience du colonialisme est élevée !':'Your awareness of colonialism is high!'; }
  else if (pct >= 50) { emoji = '🛡️'; title = lang==='ar'?'جيد':lang==='fr'?'Bien':'Good'; desc = lang==='ar'?'أنت على الطريق الصحيح. طوّر وعيك أكثر.':lang==='fr'?'Vous êtes sur la bonne voie. Développez votre conscience.':'You\'re on the right track. Develop your awareness more.'; }
  else { emoji = '📢'; title = lang==='ar'?'حان وقت الوعي':lang==='fr'?'Il est temps de s\'éveiller':'Time to Wake Up'; desc = lang==='ar'?'أنت بحاجة لمزيد من الوعي. ابدأ بقراءة البطاقات.':lang==='fr'?'Vous avez besoin de plus de conscience. Commencez par les cartes.':'You need more awareness. Start by reading the cards.'; }
  const result = document.getElementById('quizResult'); result.classList.remove('hidden');
  result.innerHTML = `<div class="qr-emoji">${emoji}</div><div class="qr-score">${pct}%</div><div class="qr-title">${title}</div><div class="qr-desc">${desc}</div><button class="quiz-submit" onclick="renderQuiz()" style="margin-top:16px">${T[lang].quizAgain}</button>`;
  result.scrollIntoView({ behavior: 'smooth' }); playSound('success');
}

