  const help = { ar:[{title:'⚠️ تنبيه',body:'لست عالماً. هذا جهد متواضع لنشر حكمة الشيخ الغزالي.'},{title:'📚 المصادر',body:'كتاب "الاستعمار أحقاد وأطماع" للشيخ محمد الغزالي، القرآن الكريم.'},{title:'✨ المميزات',body:'ثلاث لغات، ٣ أنماط، ٢٠ بطاقة، ٥ حلول للمقاومة، تتبع العادات، اختبار.'},{title:'⌨️ اختصارات',body:'الأسهم للتنقل. Escape لإغلاق اللوحات.'}], en:[{title:'⚠️ Disclaimer',body:'I am not a scholar. This is a humble effort to share Sheikh al-Ghazali\'s wisdom.'},{title:'📚 Sources',body:'"Colonialism: Grudges and Greed" by Sheikh al-Ghazali, the Holy Quran.'},{title:'✨ Features',body:'Three languages, 3 themes, 20 cards, 5 resistance solutions, habit tracker, quiz.'},{title:'⌨️ Shortcuts',body:'Arrow keys to navigate. Escape to close panels.'}], fr:[{title:'⚠️ Avertissement',body:'Je ne suis pas un savant. C\'est un effort humble pour partager la sagesse du Sheikh.'},{title:'📚 Sources',body:'« Le Colonialisme » par Sheikh al-Ghazali, le Saint Coran.'},{title:'✨ Fonctionnalités',body:'Trois langues, 3 thèmes, 20 cartes, 5 solutions de résistance, habitudes, quiz.'},{title:'⌨️ Raccourcis',body:'Flèches pour naviguer. Échap pour fermer.'}] };
