function renderDuas() { document.getElementById('duaPanelContent').innerHTML = DUAS.map(d => { const dd = d[lang]; return `<div class="dua-item"><div class="dua-item-label">${dd.label}</div><div class="dua-item-ar">${dd.text}</div><div class="dua-item-tr">${dd.tr}</div></div>`; }).join(''); }

function initScrollReveal() { if (!('IntersectionObserver' in window)) return; const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('revealed'); observer.unobserve(entry.target); } }); }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' }); document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el => observer.observe(el)); document.querySelectorAll('.tab').forEach(tab => { tab.addEventListener('click', () => setTimeout(() => { document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el => observer.observe(el)); }, 100)); }); }

function initKeyboardNav() { document.addEventListener('keydown', (e) => { if (e.key === 'Escape') { const helpPanel = document.getElementById('helpPanel'); if (!helpPanel.classList.contains('hidden')) { toggleHelp(); return; } const duaPanel = document.getElementById('duaPanel'); if (!duaPanel.classList.contains('hidden')) { toggleDuaPanel(); return; } document.querySelectorAll('.principle-card.open').forEach(c => c.classList.remove('open')); } if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') { const cardsPanel = document.getElementById('panel-cards'); if (!cardsPanel || !cardsPanel.classList.contains('active')) return; if (document.activeElement && document.activeElement.id === 'cardsSearch') return; e.preventDefault(); const cards = Array.from(document.querySelectorAll('.principle-card')).filter(c => c.style.display !== 'none'); if (cards.length === 0) return; if (currentCardIdx >= 0 && currentCardIdx < cards.length) cards[currentCardIdx].classList.remove('open'); const dir = (document.documentElement.dir === 'rtl') ? (e.key === 'ArrowRight' ? -1 : 1) : (e.key === 'ArrowRight' ? 1 : -1); currentCardIdx = Math.max(0, Math.min(cards.length - 1, currentCardIdx + dir)); cards[currentCardIdx].classList.add('open'); cards[currentCardIdx].scrollIntoView({ behavior: 'smooth', block: 'center' }); playSound('click'); } }); }

function toggleCard(id) { const card = document.getElementById(id); if (card) { card.classList.toggle('open'); playSound('click'); } }
function toggleHelp() { document.getElementById('helpPanel').classList.toggle('hidden'); playSound('click'); }
function toggleDuaPanel() { document.getElementById('duaPanel').classList.toggle('hidden'); playSound('click'); }
function showToast(msg) { const t = document.getElementById('toast'); const m = document.getElementById('toastMsg'); if (t && m) { m.textContent = msg; t.style.display = 'block'; setTimeout(() => t.style.display = 'none', 2500); } }
function initScrollTop() { const btn = document.getElementById('scrollTop'); window.addEventListener('scroll', () => { if (btn) btn.classList.toggle('visible', window.scrollY > 300); }); }

const AudioCtx = window.AudioContext || window.webkitAudioContext; let audioCtx;
function playSound(type) { try { if (!audioCtx) audioCtx = new AudioCtx(); const osc = audioCtx.createOscillator(); const gain = audioCtx.createGain(); osc.connect(gain); gain.connect(audioCtx.destination); gain.gain.value = 0.06; if (type === 'click') { osc.frequency.value = 800; osc.type = 'sine'; gain.gain.value = 0.04; } else if (type === 'success') { osc.frequency.value = 523; osc.type = 'sine'; } else if (type === 'theme') { osc.frequency.value = 440; osc.type = 'triangle'; gain.gain.value = 0.05; } osc.start(); osc.stop(audioCtx.currentTime + 0.1); } catch(e) {} }

function initSwipeGestures() { let touchStartX = 0, touchStartY = 0; const tabOrder = ['home','cards','resistance','habits','quiz','about']; document.addEventListener('touchstart', (e) => { touchStartX = e.changedTouches[0].screenX; touchStartY = e.changedTouches[0].screenY; }, { passive: true }); document.addEventListener('touchend', (e) => { const dx = e.changedTouches[0].screenX - touchStartX; const dy = e.changedTouches[0].screenY - touchStartY; if (Math.abs(dx) < 60 || Math.abs(dy) > Math.abs(dx) * 0.7) return; const currentTab = document.querySelector('.tab.active'); if (!currentTab) return; const currentIdx = tabOrder.indexOf(currentTab.dataset.tab); const isRTL = document.documentElement.dir === 'rtl'; let nextIdx; if (dx > 0) nextIdx = isRTL ? currentIdx + 1 : currentIdx - 1; else nextIdx = isRTL ? currentIdx - 1 : currentIdx + 1; nextIdx = Math.max(0, Math.min(tabOrder.length - 1, nextIdx)); if (nextIdx !== currentIdx) { const nextTab = document.querySelector(`[data-tab="${tabOrder[nextIdx]}"]`); if (nextTab) nextTab.click(); } }, { passive: true }); }

function initParticles() { const canvas = document.createElement('canvas'); canvas.className = 'particles-canvas'; document.body.appendChild(canvas); const ctx = canvas.getContext('2d'); let particles = []; const colors = ['rgba(62,39,35,0.12)','rgba(93,64,55,0.1)','rgba(121,85,72,0.08)','rgba(78,52,46,0.1)']; function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; } resize(); window.addEventListener('resize', resize); for (let i = 0; i < 20; i++) particles.push({ x:Math.random()*canvas.width, y:Math.random()*canvas.height, r:Math.random()*4+2, vy:-(Math.random()*0.3+0.1), vx:(Math.random()-0.5)*0.2, color:colors[Math.floor(Math.random()*colors.length)] }); function draw() { ctx.clearRect(0, 0, canvas.width, canvas.height); particles.forEach(p => { ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI*2); ctx.fillStyle = p.color; ctx.fill(); p.y += p.vy; p.x += p.vx; if (p.y < -10) { p.y = canvas.height + 10; p.x = Math.random() * canvas.width; } if (p.x < -10) p.x = canvas.width + 10; if (p.x > canvas.width + 10) p.x = -10; }); requestAnimationFrame(draw); } draw(); }
